import React, { useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useSelector } from 'react-redux';
import friendService from '../api/services/friendService';
import { NODE_API } from '../api/config';
import { toast } from 'react-toastify';
import './Search.css';

const Search = () => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);
  const [searching, setSearching] = useState(false);
  const [hasSearched, setHasSearched] = useState(false);
  const { user } = useSelector((state) => state.auth);
  const navigate = useNavigate();

  const getImageUrl = (path) => {
    if (!path) return null;
    if (path.startsWith('http')) return path;
    return `${NODE_API}/${path}`;
  };

  const handleSearch = useCallback(async (e) => {
    e?.preventDefault();
    if (!query.trim()) return;
    setSearching(true);
    setHasSearched(true);
    try {
      const response = await friendService.searchUser({ searchText: query.trim(), skip: 0, limit: 50 });
      const res = response.data;
      const users = res?.data?.customerData || res?.customerData || [];
      setResults(users.filter((u) => u._id !== user?._id));
    } catch (error) {
      toast.error('Search failed');
      setResults([]);
    }
    setSearching(false);
  }, [query, user]);

  const handleSendRequest = async (userId) => {
    try {
      await friendService.sendFriendRequest({ friendId: userId });
      toast.success('Friend request sent!');
      setResults((prev) => prev.map((u) =>
        u._id === userId ? { ...u, requestSent: true } : u
      ));
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to send request');
    }
  };

  return (
    <div className="search-page">
      <div className="search-header">
        <button className="search-back-btn" onClick={() => navigate(-1)}>←</button>
        <form className="search-form" onSubmit={handleSearch}>
          <input
            type="text"
            className="search-input"
            placeholder="Search users..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            autoFocus
          />
          {query && (
            <button type="button" className="search-clear-btn" onClick={() => { setQuery(''); setResults([]); setHasSearched(false); }}>
              ✕
            </button>
          )}
          <button type="submit" className="search-submit-btn" disabled={searching}>
            🔍
          </button>
        </form>
      </div>

      <div className="search-results">
        {searching && <div className="search-loading"><div className="page-loading-spinner" /></div>}

        {hasSearched && !searching && results.length === 0 && (
          <div className="search-empty">No users found for "{query}"</div>
        )}

        {!hasSearched && !searching && (
          <div className="search-empty">Search for users by name</div>
        )}

        {results.map((u) => {
          const name = u.fullName || '';
          const avatar = getImageUrl(u.imageURL?.thumbnail || u.imageURL);
          return (
            <div key={u._id} className="search-user-card">
              <div className="search-user-info" onClick={() => navigate(`/user/${u._id}`)}>
                {avatar ? (
                  <img src={avatar} alt="" className="search-user-avatar" />
                ) : (
                  <div className="search-user-avatar-placeholder">
                    {(name[0] || 'U').toUpperCase()}
                  </div>
                )}
                <div>
                  <span className="search-user-name">{name}</span>
                  {u.city && <span className="search-user-city">📍 {u.city}</span>}
                </div>
              </div>
              <div className="search-user-action">
                {u.isFriend ? (
                  <button className="search-action-btn search-msg-btn" onClick={() => navigate(`/chat/${u._id}`)}>
                    💬
                  </button>
                ) : u.requestSent || u.isFriendRequestSend ? (
                  <button className="search-action-btn search-pending-btn" disabled>
                    ⏳
                  </button>
                ) : (
                  <button className="search-action-btn search-add-btn" onClick={() => handleSendRequest(u._id)}>
                    ➕
                  </button>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default Search;
